import{_ as a,c as l,o as s,a1 as t}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse('{"title":"Совместимость: навыки Claude Code | opencode-agent-skills","description":"Узнайте, как OpenCode Agent Skills обеспечивает совместимость с навыками и системой плагинов Claude Code. Освойте механизм отображения инструментов, приоритетность обнаружения навыков и повторное использование экосистемы навыков Claude.","frontmatter":{"title":"Совместимость: навыки Claude Code | opencode-agent-skills","sidebarTitle":"Повторное использование навыков Claude","subtitle":"Совместимость навыков Claude Code","description":"Узнайте, как OpenCode Agent Skills обеспечивает совместимость с навыками и системой плагинов Claude Code. Освойте механизм отображения инструментов, приоритетность обнаружения навыков и повторное использование экосистемы навыков Claude.","tags":["Совместимость","Claude Code","Повторное использование навыков"],"prerequisite":["start-what-is-opencode-agent-skills","platforms-skill-discovery-mechanism"],"order":1},"headers":[],"relativePath":"ru/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md","filePath":"ru/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"}'),d={name:"ru/joshuadavidthomas/opencode-agent-skills/advanced/claude-code-compatibility/index.md"};function o(i,e,n,r,c,p){return s(),l("div",null,[...e[0]||(e[0]=[t(`<h1 id="совместимость-навыков-claude-code" tabindex="-1">Совместимость навыков Claude Code <a class="header-anchor" href="#совместимость-навыков-claude-code" aria-label="Permalink to &quot;Совместимость навыков Claude Code&quot;">​</a></h1><h2 id="что-вы-сможете-делать-после-изучения" tabindex="-1">Что вы сможете делать после изучения <a class="header-anchor" href="#что-вы-сможете-делать-после-изучения" aria-label="Permalink to &quot;Что вы сможете делать после изучения&quot;">​</a></h2><ul><li>Понять, как плагины автоматически обеспечивают совместимость с форматом навыков Claude Code</li><li>Освоить механизм отображения инструментов, чтобы навыки Claude работали корректно в OpenCode</li><li>Узнать полные правила приоритетности обнаружения навыков</li><li>Повторно использовать существующие навыки из плагин-рынка Claude без переписывания</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>У вас уже есть несколько навыков Claude Code, или вы хотите использовать навыки из плагин-рынка Claude, но эти навыки написаны специально для Claude Code. При прямом использовании в OpenCode возникают проблемы:</p><ul><li>Вызовы инструментов в навыках Claude (например, <code>TodoWrite</code>, <code>Task</code>) не существуют в OpenCode</li><li>Неясно, как заставить OpenCode находить установленные плагины навыков Claude</li><li>Беспокойство о несовместимости форматов навыков, требующее полного переписывания</li></ul><h2 id="основная-концепция" tabindex="-1">Основная концепция <a class="header-anchor" href="#основная-концепция" aria-label="Permalink to &quot;Основная концепция&quot;">​</a></h2><p>Плагин OpenCode Agent Skills обеспечивает <strong>трёхуровневый механизм совместимости</strong>, позволяющий использовать навыки Claude Code без модификаций:</p><ol><li><strong>Автоматическое обнаружение</strong> — сканирование навыков из стандартных директорий Claude Code (<code>.claude/skills/</code>, <code>~/.claude/plugins/</code>)</li><li><strong>Отображение инструментов</strong> — автоматическая инъекция руководства по отображению инструментов при загрузке навыков, преобразующая имена инструментов Claude в имена инструментов OpenCode</li><li><strong>Поддержка форматов</strong> — одновременная поддержка v1 и v2 форматов установки плагинов Claude</li></ol><div class="info custom-block"><p class="custom-block-title">Ключевая концепция</p><p><strong>Формат навыков Claude Code</strong> — спецификация навыков, определённая Anthropic, использующая файлы <code>SKILL.md</code> для описания навыков, содержащие YAML frontmatter (метаданные) и Markdown контент (инструкции).</p></div><h3 id="принцип-отображения-инструментов" tabindex="-1">Принцип отображения инструментов <a class="header-anchor" href="#принцип-отображения-инструментов" aria-label="Permalink to &quot;Принцип отображения инструментов&quot;">​</a></h3><p>Когда плагин обнаруживает, что загружаемый навык написан для Claude Code, он автоматически инъецирует руководство по отображению инструментов:</p><table tabindex="0"><thead><tr><th>Инструмент Claude Code</th><th>Инструмент OpenCode</th><th>Правило отображения</th></tr></thead><tbody><tr><td><code>TodoWrite/TodoRead</code></td><td><code>todowrite/todoread</code></td><td>нижний регистр</td></tr><tr><td><code>Task</code> (субагент)</td><td><code>task</code> (с параметром subagent_type)</td><td>изменить на параметр</td></tr><tr><td><code>Skill</code></td><td><code>use_skill</code></td><td>заменить имя инструмента</td></tr><tr><td><code>Read/Write/Edit/Bash/Glob/Grep/WebFetch</code></td><td><code>read/write/edit/bash/glob/grep/webfetch</code></td><td>нижний регистр</td></tr></tbody></table><p><strong>Способ отображения</strong>: Плагин инъецирует руководство по отображению как XML в контекст сессии при загрузке навыков, и AI автоматически вызывает правильные инструменты согласно отображению.</p><div class="tip custom-block"><p class="custom-block-title">Зачем нужно отображение?</p><p>Claude Code и OpenCode используют разные стили именования инструментов. Claude использует PascalCase (например, <code>TodoWrite</code>), OpenCode использует нижний регистр (например, <code>todowrite</code>). Отображение инструментов сообщает AI, как выполнять преобразование вызовов.</p></div><h3 id="приоритетность-обнаружения-навыков" tabindex="-1">Приоритетность обнаружения навыков <a class="header-anchor" href="#приоритетность-обнаружения-навыков" aria-label="Permalink to &quot;Приоритетность обнаружения навыков&quot;">​</a></h3><p>Плагин обнаруживает навыки в следующем порядке, <strong>первый найденный навык имеет приоритет</strong> (навыки с одинаковым именем не дублируются):</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Процесс обнаружения навыков] --&gt; B[Проектный уровень OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; |.opencode/skills/| C[1. project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[Проектный уровень Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; |.claude/skills/| E[2. claude-project]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[Пользовательский уровень OpenCode]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; |~/.config/opencode/skills/| G[3. user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Пользовательский уровень Claude Code]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; |~/.claude/skills/| I[4. claude-user]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt; J[Кэш плагинов Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; |~/.claude/plugins/cache/| K[5. claude-plugins]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; L[Плагин-рынок Claude]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; |~/.claude/plugins/marketplaces/| M[6. claude-plugins]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style C fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style E fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style G fill:#e1f5e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style I fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style K fill:#fff4e1</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    style M fill:#fff4e1</span></span></code></pre></div><p><strong>Правила приоритетности</strong>:</p><ul><li>Проектные навыки перекрывают пользовательские навыки (удобно для кастомизации проектов)</li><li>Навыки OpenCode имеют приоритет над навыками Claude (избежание путаницы)</li><li>Навыки с одинаковыми именами сохраняют только первую найденную версию</li></ul><details class="details custom-block"><summary>Пример: перекрытие навыков с одинаковыми именами</summary><p>Предположим, у вас есть навык с именем <code>git-helper</code> в двух местах:</p><ul><li><code>.claude/skills/git-helper/SKILL.md</code> (версия Claude)</li><li><code>.opencode/skills/git-helper/SKILL.md</code> (версия OpenCode)</li></ul><p><strong>Результат</strong>: версия OpenCode вступает в силу (более высокий приоритет)</p></details><h2 id="🎒-подготовка-к-началу" tabindex="-1">🎒 Подготовка к началу <a class="header-anchor" href="#🎒-подготовка-к-началу" aria-label="Permalink to &quot;🎒 Подготовка к началу&quot;">​</a></h2><ul><li>Установлен и настроен плагин OpenCode Agent Skills</li><li>Понимание базовых концепций навыков (рекомендуется сначала прочитать <a href="./../../start/what-is-opencode-agent-skills/">Что такое OpenCode Agent Skills?</a>)</li><li>(Необязательно) Имеются установленные плагины или навыки Claude Code</li></ul><h2 id="следуите-за-мнои" tabindex="-1">Следуйте за мной <a class="header-anchor" href="#следуите-за-мнои" aria-label="Permalink to &quot;Следуйте за мной&quot;">​</a></h2><h3 id="шаг-1-проверьте-обнаружение-навыков-claude" tabindex="-1">Шаг 1: Проверьте обнаружение навыков Claude <a class="header-anchor" href="#шаг-1-проверьте-обнаружение-навыков-claude" aria-label="Permalink to &quot;Шаг 1: Проверьте обнаружение навыков Claude&quot;">​</a></h3><p><strong>Зачем</strong> Убедитесь, что плагин правильно сканирует вашу директорию навыков Claude Code.</p><p>Вызовите инструмент в OpenCode:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_available_skills()</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: возвращаемый список навыков включает навыки из <code>.claude/skills/</code>, <code>~/.claude/skills/</code>, <code>~/.claude/plugins/</code>, где поле <code>source</code> каждого навыка показывает источник (например, <code>claude-project</code>, <code>claude-user</code>, <code>claude-plugins</code>).</p><p><strong>Проверочная точка ✅</strong>: Подтвердите, что список содержит ожидаемые навыки Claude.</p><h3 id="шаг-2-загрузите-навык-claude" tabindex="-1">Шаг 2: Загрузите навык Claude <a class="header-anchor" href="#шаг-2-загрузите-навык-claude" aria-label="Permalink to &quot;Шаг 2: Загрузите навык Claude&quot;">​</a></h3><p><strong>Зачем</strong> Проверьте, правильно ли работает механизм отображения инструментов.</p><p>Вызовите инструмент для загрузки навыка Claude:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>use_skill(skill=&quot;your-skill-name&quot;)</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: возвращаемое сообщение об успехе, например <code>Skill &quot;xxx&quot; loaded.</code>.</p><p><strong>Проверочная точка ✅</strong>: AI теперь может использовать инструкции этого навыка.</p><h3 id="шаг-3-проверьте-что-отображение-инструментов-работает" tabindex="-1">Шаг 3: Проверьте, что отображение инструментов работает <a class="header-anchor" href="#шаг-3-проверьте-что-отображение-инструментов-работает" aria-label="Permalink to &quot;Шаг 3: Проверьте, что отображение инструментов работает&quot;">​</a></h3><p><strong>Зачем</strong> Убедитесь, что AI правильно вызывает инструменты OpenCode, а не инструменты Claude.</p><p>Задайте AI задачу, требующую использования инструментов этого навыка, например:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Пожалуйста, используйте функцию todo в навыке, чтобы создать список задач для меня.</span></span></code></pre></div><p><strong>Что вы должны увидеть</strong>: AI правильно вызывает инструмент <code>todowrite</code> OpenCode, а не инструмент <code>TodoWrite</code> Claude.</p><div class="tip custom-block"><p class="custom-block-title">Как проверить, что отображение работает?</p><p>Посмотрите журнал вызовов инструментов AI (если включён режим отладки), вы увидите, что он вызывает <code>todowrite</code>, а не <code>TodoWrite</code>.</p></div><p><strong>Проверочная точка ✅</strong>: Вызов инструмента успешен, задача завершена.</p><h2 id="предупреждения-о-подводных-камнях" tabindex="-1">Предупреждения о подводных камнях <a class="header-anchor" href="#предупреждения-о-подводных-камнях" aria-label="Permalink to &quot;Предупреждения о подводных камнях&quot;">​</a></h2><h3 id="_1-несоответствие-формата-плагинов" tabindex="-1">1. Несоответствие формата плагинов <a class="header-anchor" href="#_1-несоответствие-формата-плагинов" aria-label="Permalink to &quot;1. Несоответствие формата плагинов&quot;">​</a></h3><p><strong>Проблема</strong>: Старые плагины Claude используют формат v1, новые — формат v2, что приводит к тому, что некоторые навыки не могут быть обнаружены.</p><p><strong>Причина</strong>: Структуры <code>installed_plugins.json</code> v1 и v2 различаются.</p><p><strong>Решение</strong>: Плагин одновременно поддерживает оба формата, ручное преобразование не требуется. Если навыки по-прежнему не обнаруживаются, проверьте, существует ли <code>~/.claude/plugins/installed_plugins.json</code> и правильный ли его формат.</p><h3 id="_2-отображение-инструментов-не-работает" tabindex="-1">2. Отображение инструментов не работает <a class="header-anchor" href="#_2-отображение-инструментов-не-работает" aria-label="Permalink to &quot;2. Отображение инструментов не работает&quot;">​</a></h3><p><strong>Проблема</strong>: AI по-прежнему вызывает имена инструментов Claude, вызывая ошибки.</p><p><strong>Причина</strong>: Содержимое навыка может обходить руководство по отображению инструментов, или используются жёстко закодированные вызовы инструментов.</p><p><strong>Решение</strong>:</p><ul><li>Подтвердите, что навык используется после загрузки, а не путём прямого вызова инструментов</li><li>Если в навыке есть примеры кода, вручную измените имена инструментов на формат OpenCode</li></ul><h3 id="_3-конфликты-имен-навыков" tabindex="-1">3. Конфликты имён навыков <a class="header-anchor" href="#_3-конфликты-имен-навыков" aria-label="Permalink to &quot;3. Конфликты имён навыков&quot;">​</a></h3><p><strong>Проблема</strong>: Навыки с одинаковыми именами в разных местах, загружается неправильная версия.</p><p><strong>Причина</strong>: Перекрытие, вызванное приоритетностью обнаружения навыков.</p><p><strong>Решение</strong>:</p><ul><li>Проверьте поле <code>source</code> навыка, чтобы подтвердить источник</li><li>Используйте формат пространства имён для явного указания источника: <code>use_skill(skill=&quot;user:skill-name&quot;)</code> или <code>use_skill(skill=&quot;claude-plugins:skill-name&quot;)</code></li></ul><details class="details custom-block"><summary>Синтаксис пространства имён</summary><p>Плагин поддерживает формат <code>namespace:skill-name</code>:</p><ul><li><code>project:skill-name</code> - проектные навыки OpenCode</li><li><code>claude-project:skill-name</code> - проектные навыки Claude</li><li><code>user:skill-name</code> - пользовательские навыки OpenCode</li><li><code>claude-user:skill-name</code> - пользовательские навыки Claude</li><li><code>claude-plugins:skill-name</code> - навыки плагин-рынка Claude</li></ul></details><h2 id="резюме-урока" tabindex="-1">Резюме урока <a class="header-anchor" href="#резюме-урока" aria-label="Permalink to &quot;Резюме урока&quot;">​</a></h2><p>Плагин OpenCode Agent Skills обеспечивает трёхуровневый механизм совместимости для бесшовного повторного использования навыков Claude Code:</p><ul><li><strong>Автоматическое обнаружение</strong> - сканирование навыков из 6 расположений, охватывающих проектный, пользовательский и плагинный уровни</li><li><strong>Отображение инструментов</strong> - автоматическое преобразование имён инструментов Claude в имена инструментов OpenCode</li><li><strong>Поддержка форматов</strong> - одновременная поддержка форматов плагинов Claude v1 и v2</li></ul><p>Нет необходимости переписывать навыки, устанавливайте и используйте напрямую, плагин автоматически обработает проблемы совместимости.</p><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>В следующем уроке мы изучим <strong><a href="./../superpowers-integration/">Интеграцию с рабочими процессами Superpowers</a></strong>.</p><p>Вы узнаете:</p><ul><li>Как включить режим Superpowers</li><li>Автоматическое обнаружение и загрузка навыков Superpowers</li><li>Как строгие рабочие процессы повышают эффективность разработки</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы развернуть и просмотреть расположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функциональность</th><th>Путь к файлу</th><th>Номера строк</th></tr></thead><tbody><tr><td>Определение отображения инструментов</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L19-L25" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>19-25</td></tr><tr><td>Определение типов форматов v1/v2</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L35-L61" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>35-61</td></tr><tr><td>Извлечение путей установки плагинов</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L68-L77" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>68-77</td></tr><tr><td>Обнаружение навыков плагинов</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L82-L105" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>82-105</td></tr><tr><td>Обнаружение навыков рынка</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L115-L180" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>115-180</td></tr><tr><td>Обнаружение кэшированных навыков</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/claude.ts#L193-L253" target="_blank" rel="noreferrer"><code>src/claude.ts</code></a></td><td>193-253</td></tr><tr><td>Список приоритетов обнаружения навыков</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L241-L254" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>241-254</td></tr><tr><td>Логика дедупликации навыков с одинаковыми именами</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L256-L260" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>256-260</td></tr><tr><td>Импорт toolTranslation</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L15" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>15</td></tr><tr><td>Инъекция отображения инструментов</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L238-L249" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>238-249</td></tr></tbody></table><p><strong>Ключевые константы</strong>:</p><ul><li><code>toolTranslation</code>: XML-строка руководства по отображению инструментов, внедряемая в контекст сессии при загрузке навыков. Определена в <code>src/claude.ts:19-25</code>, импортирована в <code>src/tools.ts:15</code></li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>getPluginInstallPaths()</code>: Извлекает пути установки плагинов из форматов v1/v2</li><li><code>discoverSkillsFromPluginDir()</code>: Сканирует поддиректорию skills/ директории плагинов</li><li><code>discoverMarketplaceSkills()</code>: Обнаруживает навыки из <code>~/.claude/plugins/marketplaces/</code> (приоритет)</li><li><code>discoverPluginCacheSkills()</code>: Обнаруживает навыки из <code>~/.claude/plugins/cache/</code> (резервный вариант)</li><li><code>findFile()</code>: Рекурсивно ищет указанное имя файла (вспомогательная функция)</li></ul><p><strong>Важные процессы</strong>:</p><ol><li>При инициализации плагина вызывается <code>discoverAllSkills()</code> → перебирает 6 путей обнаружения</li><li>При обнаружении навыков плагинов Claude вызывается <code>discoverMarketplaceSkills()</code> или <code>discoverPluginCacheSkills()</code></li><li>При загрузке навыков инструмент <code>use_skill</code> вставляет <code>toolTranslation</code> в XML-контент (строка 244)</li></ol></details>`,68)])])}const g=a(d,[["render",o]]);export{h as __pageData,g as default};
